/**
 * 极简版关键字世界书：直接控制条目的开启 (enabled = true) 与关闭 (enabled = false)
 */

type SimpleKeywordRule = {
    keywords: string[];
    entryNameIncludes: string;
    missThreshold: number; // 连续多少条 AI 回复没有提到关键字就关闭
};

// 【小白配置区】在这里添加你想要的关键字和条目
const RULES: SimpleKeywordRule[] = [
    {
        keywords: ["蒂薇儿"],     // 检测到的关键字
        entryNameIncludes: "蒂薇儿",  // 对应的世界书条目名称（包含即可）
        missThreshold: 2             // 连续 2 次 AI 回复没提到就关闭
    }
];

const SCAN_MESSAGES = 20; // 往前扫描的最大消息数

/**
 * 判断指定规则在当前聊天上下文下是否应该处于“开启”状态
 */
function shouldEnableEntry(rule: SimpleKeywordRule): boolean {
    try {
        const lastId = getLastMessageId();
        if (lastId < 0) return false;
        
        const messages = getChatMessages(`0-${lastId}`);
        // 只取最近的若干条消息
        const recentMessages = messages.slice(Math.max(0, messages.length - SCAN_MESSAGES));
        
        let aiMissCount = 0;
        
        // 从最新的消息往回找
        for (let i = recentMessages.length - 1; i >= 0; i--) {
            const msg = recentMessages[i];
            const text = String(msg.message || "");
            
            // 只要没达到关闭阈值，只要在这之前的任何消息里发现了关键字，就保持开启
            const foundKeyword = rule.keywords.some(k => text.includes(k));
            if (foundKeyword) {
                return true;
            }
            
            // 判断是否是 AI 回复，统计 AI 未提到关键字的次数
            const isUser = msg.is_user === true || msg.is_user === "true" || msg.is_user === 1;
            if (!isUser) {
                aiMissCount++;
                if (aiMissCount >= rule.missThreshold) {
                    return false; // 已经连续若干条 AI 回复没有提到了，关闭
                }
            }
        }
        
        return false; // 整个记录里都没有，关闭
    } catch (e) {
        return false;
    }
}

async function syncWorldbookSwitches() {
    try {
        // 获取当前角色绑定的主世界书
        const primaryWb = (() => {
            try {
                const { primary } = getCharWorldbookNames("current");
                return primary?.trim() || null;
            } catch {
                return null;
            }
        })();

        if (!primaryWb) return;

        // 使用 updateWorldbookWith 直接修改条目的 enabled 属性
        await updateWorldbookWith(primaryWb, entries => {
            let changed = false;
            
            // 计算每个规则应该处于的状态
            const targetStates = RULES.map(rule => ({
                rule,
                shouldBeEnabled: shouldEnableEntry(rule)
            }));
            
            for (const entry of entries) {
                if (!entry.name) continue;
                
                // 找到第一个匹配该条目的规则
                const matchedTarget = targetStates.find(t => entry.name.includes(t.rule.entryNameIncludes));
                
                if (matchedTarget) {
                    // 如果状态不一致，就进行切换
                    if (entry.enabled !== matchedTarget.shouldBeEnabled) {
                        entry.enabled = matchedTarget.shouldBeEnabled;
                        changed = true;
                        // console.log(`[简单关键字开关] 条目「${entry.name}」已${entry.enabled ? "开启" : "关闭"}`);
                    }
                }
            }
            
            return entries; // 返回修改后的 entries 数组，Tavern Helper 会自动保存回游戏
        });
    } catch (e) {
        console.error("[简单关键字开关] 同步失败:", e);
    }
}

let debounceTimer: ReturnType<typeof setTimeout> | null = null;
function scheduleSwitchSync() {
    if (debounceTimer) clearTimeout(debounceTimer);
    debounceTimer = setTimeout(() => {
        debounceTimer = null;
        void errorCatched(syncWorldbookSwitches)();
    }, 450);
}

$(() => {
    errorCatched(() => {
        console.info(`[简单关键字开关] 脚本已加载，已配置 ${RULES.length} 条规则`);
        void syncWorldbookSwitches();
        
        eventOn(tavern_events.MESSAGE_SENT, scheduleSwitchSync);
        eventOn(tavern_events.MESSAGE_RECEIVED, scheduleSwitchSync);
        eventOn(tavern_events.CHAT_CHANGED, scheduleSwitchSync);
        eventOn(tavern_events.CHARACTER_PAGE_LOADED, scheduleSwitchSync);
        eventOn(tavern_events.MESSAGE_UPDATED, scheduleSwitchSync);
    })();
});
